import{_ as s,o as l,c as n,O as t}from"./chunks/framework.0d5b6918.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"materials/source-delivery-boundaries.md","filePath":"materials/source-delivery-boundaries.md","lastUpdated":1776338371000}'),e={name:"materials/source-delivery-boundaries.md"};function r(i,a,c,p,d,_){return l(),n("div",null,a[0]||(a[0]=[t('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Delivery Scope</p><h1>源码交付与授权边界说明</h1><div class="brand-hero__panel"><span class="brand-pill">Client Delivery Scope</span><strong>如果您正在评估部署方式、后续维护或源码控制权，这页用于说明标准交付、私有化部署和源码授权之间的区别。</strong><p>重点是把交付范围、授权方式和维护责任在报价前先说清楚，避免双方理解不一致。</p></div><p class="brand-lead"> 当前通常分成三种模式： <strong>标准交付、私有化部署、源码授权 / 买断</strong>。 是否包含源码，不只取决于是否独立部署，还取决于双方约定的授权范围和后续维护方式。 </p><div class="brand-chip-list"><span class="brand-chip">标准交付</span><span class="brand-chip">私有化交付</span><span class="brand-chip">源码授权</span><span class="brand-chip">合同明确</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./service-packages.html">看服务包与启动方式</a><a class="cta-button" href="../product/deliverables.html">看客户交付说明与文档入口</a><a class="cta-button" href="../product/customer-flow.html">看客户交付与使用说明</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECFABRIC // DELIVERY SCOPE</span><span>MAT 10</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">standard</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">usable_delivery</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">private</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">independent_environment</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">source</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">licensed_separately</span></span></div><div class="matrix-panel__callout">CLARIFY SCOPE BEFORE DELIVERY</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">goal</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">clear scope</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">delivery + license</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">mode</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">project discussion</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Mode 01</p><h2>标准交付</h2><p>更适合先关注“系统能不能稳定运行、能不能正式验收”的场景，默认不包含整仓源码移交。</p></article><article class="brand-card"><p class="brand-kicker">Mode 02</p><h2>私有化交付</h2><p>更适合需要独立服务器、独立数据库、独立域名和独立运行环境的场景，但源码范围仍需单独约定。</p></article><article class="brand-card"><p class="brand-kicker">Mode 03</p><h2>源码授权 / 买断</h2><p>更适合明确需要后续自行维护、二开或更高控制权的场景，应作为单独授权模式处理。</p></article></section><section class="brand-card"><p class="brand-kicker">Pricing Boundary</p><h2>三种交付与授权边界</h2><table class="cooperation-start-table"><thead><tr><th>模式</th><th>默认交付内容</th><th>源码状态</th><th>适合场景</th></tr></thead><tbody><tr><td>标准交付</td><td>部署完成的系统、访问入口、账号、说明文档、结果入口、必要配置交接</td><td>默认不交整仓源码</td><td>先关注可运行结果、正式验收和稳定使用的场景</td></tr><tr><td>私有化交付</td><td>客户独立环境部署、部署手册、参数清单、运维交接、验收支持</td><td>源码范围需单独约定</td><td>客户要求独立服务器、独立部署、内网或更强边界</td></tr><tr><td>源码授权 / 买断</td><td>项目范围内代码、部署脚本、必要说明、授权边界约定</td><td>单独授权、单独报价</td><td>客户明确要求源码控制权，并愿意为此付更高成本</td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Quick Summary</p><h2>先看这 4 句话</h2><ul class="brand-list"><li>标准交付默认聚焦可运行结果、账号、文档和交付说明。</li><li>私有化部署默认聚焦独立环境、部署交接和验收支持。</li><li>独立部署不自动等于整仓源码买断。</li><li>如果需要源码交接、二开或更高控制权，会在报价和合同里单独明确。</li></ul></article><article class="brand-card"><p class="brand-kicker">Clarification</p><h2>为什么独立部署不一定等于源码买断</h2><ul class="brand-list"><li>很多项目的核心诉求是“可运行、可验收、可长期使用”，而不是立即接手整套代码。</li><li>平台型项目通常同时包含通用底座、项目范围内实现和交付说明，源码范围需要按约定划清。</li><li>如果您需要后续自行维护、二开或更高控制权，可以改成源码授权或买断模式。</li><li>这样对双方的维护责任、升级方式和费用边界都会更清晰。</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Contract Wording</p><h2>可直接写进方案或合同的 3 段说明</h2><div class="brand-grid brand-grid--three"><article class="brand-card brand-card--nested"><h3>1. 标准交付说明</h3><p>本次报价包含项目范围内的功能实现、部署落地、账号与文档交接，以及约定周期内的问题修复与验收支持；默认不包含整仓源码移交和永久买断授权。</p></article><article class="brand-card brand-card--nested"><h3>2. 私有化部署说明</h3><p>本次交付按客户独立服务器、独立数据库和独立域名部署执行，交付内容包括运行环境、部署手册、参数清单和验收支持；如需源码交接或更高授权边界，需在私有化基础上单独约定。</p></article><article class="brand-card brand-card--nested"><h3>3. 源码授权说明</h3><p>如需项目范围内源码交接、后续自行维护或更高控制权，本次将按源码授权或买断模式单独报价；报价将明显高于普通实施和部署交付，不与标准项目交付包混算。</p></article></div></section><section class="brand-card"><p class="brand-kicker">Project Scope</p><h2>如果您明确需要源码，请先确认这 4 个问题</h2><ol class="brand-list"><li>交的是整仓，还是只交本次项目范围内的代码。</li><li>是否拥有后续自行修改和二次分发权。</li><li>源码交付后，后续维护责任还由谁承担。</li><li>通用底座、其他客户相关内容和内部文档是否排除在本次交付范围外。</li></ol></section></div>',1)]))}const b=s(e,[["render",r]]);export{m as __pageData,b as default};
